import{c as o,Q as r,j as t,m as a}from"./chunks/framework.CBiVa4O3.js";const b=JSON.parse('{"title":"Go 与 Kubernetes：Operator 开发基础","description":"","frontmatter":{},"headers":[],"relativePath":"../goLearning/29-Go与Kubernetes：Operator开发基础.md","filePath":"../goLearning/29-Go与Kubernetes：Operator开发基础.md","lastUpdated":1778496697000}'),l={name:"../goLearning/29-Go与Kubernetes：Operator开发基础.md"};function i(n,e,s,d,p,c){return r(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="go-与-kubernetes-operator-开发基础" tabindex="-1">Go 与 Kubernetes：Operator 开发基础 <a class="header-anchor" href="#go-与-kubernetes-operator-开发基础" aria-label="Permalink to &quot;Go 与 Kubernetes：Operator 开发基础&quot;">​</a></h1><blockquote><p><strong>导读</strong>：Kubernetes (K8s)、Docker、Prometheus 全是用 Go 写的。如果你想在云原生领域玩转甚至扩展基础设施，Go 是唯一的门票。</p></blockquote><h2 id="一、什么是-operator" tabindex="-1">一、什么是 Operator？ <a class="header-anchor" href="#一、什么是-operator" aria-label="Permalink to &quot;一、什么是 Operator？&quot;">​</a></h2><p>Kubernetes 原生提供了 Pod, Deployment, Service 等资源。但如果你的业务是一个分布式数据库集群（如 Redis Cluster / MySQL MHA），普通的 Deployment 无法处理主从切换、数据备份等复杂运维逻辑。 <strong>Operator 就是一个运行在 K8s 里的“机器人”</strong>。你把运维知识写成代码（控制器），它时刻监听 K8s 集群状态，自动帮你扩容、备份和处理故障。</p><h2 id="二、k8s-的声明式-api-机制" tabindex="-1">二、K8s 的声明式 API 机制 <a class="header-anchor" href="#二、k8s-的声明式-api-机制" aria-label="Permalink to &quot;二、K8s 的声明式 API 机制&quot;">​</a></h2><p>K8s 不是命令式的（请帮我新建 3 个 Pod），而是声明式的（我希望系统里存在 3 个 Pod 并且状态正常）。 Operator 的核心是 <strong>Reconciliation Loop（调谐循环）</strong>：</p><ol><li>观察（Observe）当前的系统实际状态。</li><li>分析（Analyze）实际状态与期望状态的差异。</li><li>行动（Act）执行创建/删除/更新，让实际状态趋近期望状态。</li></ol><h2 id="三、开发利器-kubebuilder" tabindex="-1">三、开发利器：Kubebuilder <a class="header-anchor" href="#三、开发利器-kubebuilder" aria-label="Permalink to &quot;三、开发利器：Kubebuilder&quot;">​</a></h2><p>官方提供了 <code>kubebuilder</code> 这个脚手架工具。</p><ol><li><p><strong>初始化项目</strong>： <code>kubebuilder init --domain mycompany.com --repo github.com/my/operator</code></p></li><li><p><strong>创建自定义资源 (CRD) 与控制器</strong>： <code>kubebuilder create api --group db --version v1alpha1 --kind RedisCluster</code> 这会为你生成两个核心文件：</p></li></ol><ul><li><code>api/v1alpha1/rediscluster_types.go</code>: 你在这里定义用户可以在 YAML 里填什么参数。</li><li><code>controllers/rediscluster_controller.go</code>: 你在这里编写核心逻辑，即上述的“调谐循环”。</li></ul><ol start="3"><li><strong>编写 Reconcile 函数</strong> 在这个函数里，你会使用 Go 调用 <code>client.Get()</code> 获取用户的期望配置，然后用 <code>client.Create()</code> 通过 K8s API 自动去拉起实际的 StatefulSet 容器组。</li></ol><p>掌握了用 Go 写 Operator，你就从“使用云”的工程师，进化成了“改造云”架构师。</p>',13)])])}const _=o(l,[["render",i]]);export{b as __pageData,_ as default};
